import { normalizeTags } from './normalizeTags';

describe('normalizeTags', () => {
  it('should handle happy path with valid tags', () => {
    const input = ['JavaScript', '  Typescript  ', 'REACT', 'Node.js'];
    const result = normalizeTags(input);
    // Expect tags to be trimmed, lowercased and deduplicated
    expect(result).toEqual(['javascript', 'typescript', 'react', 'node.js']);
  });

  it('should handle edge case with duplicate and mixed case tags', () => {
    const input = ['Python', 'python', ' PYTHON ', 'Django', 'django'];
    const result = normalizeTags(input);
    expect(result).toEqual(['python', 'django']);
  });

  it('should handle null/empty input', () => {
    // default empty array
    expect(normalizeTags()).toEqual([]);
    // explicit null and undefined should be treated as empty
    expect(normalizeTags(null as unknown as any)).toEqual([]);
    expect(normalizeTags(undefined as unknown as any)).toEqual([]);
    // empty string inside array
    expect(normalizeTags(['', '  '])).toEqual([]);
    // zero value inside array
    expect(normalizeTags([0 as unknown as any])).toEqual([]);
  });
});

